/** 
 * Forensic Cash Flow Master Engine
 * Optimized for the "Real Money" Backend
 */
const inr = v => '₹' + Math.abs(Number(v)).toLocaleString('en-IN', {
  maximumFractionDigits: 0
});
const fmt_date = iso => {
  const d = new Date(iso);
  return isNaN(d.getTime()) ? '—' : d.toLocaleDateString('en-IN', {
    day: '2-digit',
    month: 'short'
  });
};

// --- DATA BINDING ---
function init() {
  if (window.appsmith && window.appsmith.model && window.appsmith.model.report) {
    render(window.appsmith.model.report);
  }
}
appsmith.onModelUpdate(() => {
  if (appsmith.model.report) render(appsmith.model.report);
});

// Initial kickstart
setTimeout(init, 500);
function render(weeks) {
  if (!weeks || !Array.isArray(weeks) || weeks.length === 0) return;
  let total_in = 0,
    total_out = 0,
    total_txn = 0,
    active_days = 0;
  let all_txns = [];
  let acct_map = {};
  weeks.forEach(week => {
    total_in += parseFloat(week.total_in || 0);
    total_out += parseFloat(week.total_out || 0);
    (week.days || []).forEach(day => {
      if (parseFloat(day.total_in) > 0 || parseFloat(day.total_out) > 0) active_days++;
      (day.categories || []).forEach(cat => {
        (cat.transactions || []).forEach(t => {
          total_txn++;
          all_txns.push(t);
          const aid = t.liquid_account_id || 'Cash/Bank';
          if (!acct_map[aid]) acct_map[aid] = {
            in: 0,
            out: 0
          };
          acct_map[aid].in += parseFloat(t.amount_in || 0);
          acct_map[aid].out += parseFloat(t.amount_out || 0);
        });
      });
    });
  });
  const net = total_in - total_out;
  const eff = Math.min(100, Math.round(total_in / (total_in + total_out || 1) * 100));

  // Update KPIs
  document.getElementById('kpi-inflow').textContent = inr(total_in);
  document.getElementById('kpi-outflow').textContent = inr(total_out);
  document.getElementById('kpi-net').textContent = inr(net);
  document.getElementById('kpi-days').textContent = active_days + ' Days';
  document.getElementById('eff-val').textContent = eff + '% Flow Efficiency';
  document.getElementById('eff-fill').style.width = eff + '%';
  document.getElementById('period-val').textContent = weeks[0].label + " - " + weeks[weeks.length - 1].label;

  // Build Account Breakdown
  let acct_html = '';
  Object.entries(acct_map).forEach(([aid, vals]) => {
    acct_html += `
      <div class="info-row">
        <span class="info-row-label"><span class="dot dot-blue"></span>Liquid Source #${aid}</span>
        <span class="info-row-val">${inr(vals.in)} in / ${inr(vals.out)} out</span>
      </div>`;
  });
  document.getElementById('acct-rows').innerHTML = acct_html;

  // Build Transaction Ledger
  let ledger_html = '';
  weeks.forEach(week => {
    ledger_html += `
      <div class="ledger-header-band">
        <div class="week-banner">
          <div class="week-banner-left">📅 ${week.label}</div>
          <div class="week-banner-right">
            <span class="flow-badge green">+${inr(week.total_in)}</span>
            <span class="flow-badge red">−${inr(week.total_out)}</span>
          </div>
        </div>
      </div>`;
    week.days.forEach(day => {
      ledger_html += `
        <div class="day-banner">
          <div class="day-banner-left">☀ ${day.display_date}</div>
          <div style="display:flex; gap:10px;"><span class="today-badge">${inr(day.total_in - day.total_out)} Net</span></div>
        </div>`;
      day.categories.forEach(cat => {
        ledger_html += `
          <div class="cat-banner">
            <span class="cat-banner-label">📄 ${cat.label}</span>
            <span class="cat-banner-total">${inr(cat.total_in || cat.net_flow)}</span>
          </div>
          <table class="txn-table">
            <tbody>
              ${cat.transactions.map(t => `
                <tr class="interactive-row">
                  <td class="txn-date">${fmt_date(t.trans_date)}</td>
                  <td><div class="txn-party">${t.party_name}</div><div class="txn-desc">${t.description}</div></td>
                  <td class="in-val">${parseFloat(t.amount_in) > 0 ? inr(t.amount_in) : '—'}</td>
                  <td class="out-val">${parseFloat(t.amount_out) > 0 ? inr(t.amount_out) : '—'}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>`;
      });
    });
  });
  document.getElementById('ledger-wrap').innerHTML = ledger_html;

  // Audit Trail
  document.getElementById('audit-count').textContent = all_txns.length + ' Ledger Entries';
  document.getElementById('audit-body').innerHTML = all_txns.map(t => `
    <tr class="audit-row">
      <td><span class="mono">${t.source_table}</span></td>
      <td><span class="mono">${t.source_id}</span></td>
      <td style="font-weight:500;">${t.party_name}</td>
      <td>${t.description}</td>
      <td><span class="chip chip-mono">ID: ${t.liquid_account_id}</span></td>
      <td class="audit-amt">${inr(t.amount_in || t.amount_out)}</td>
    </tr>
  `).join('');
}

